namespace InventoryApp.Models;

public class EquipmentItem
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Location { get; set; } = string.Empty;
    public DateTime LastInspected { get; set; }
}

using InventoryApp.Models;

namespace InventoryApp.Services;

public class EquipmentService
{
    public async Task<List<EquipmentItem>> GetEquipmentAsync()
    {
        // Simulate network/database latency
        await Task.Delay(500);

        return new List<EquipmentItem>
        {
            new() { Id = 1, Name = "Forklift A", Location = "Warehouse 1", LastInspected = new DateTime(2026, 3, 15) },
            new() { Id = 2, Name = "Conveyor Belt B", Location = "Warehouse 2", LastInspected = new DateTime(2026, 4, 20) },
            new() { Id = 3, Name = "Hydraulic Press", Location = "Shop Floor", LastInspected = new DateTime(2026, 1, 10) },
            new() { Id = 4, Name = "CNC Lathe", Location = "Machine Room", LastInspected = new DateTime(2026, 5, 1) },
            new() { Id = 5, Name = "Welding Station 3", Location = "Bay C", LastInspected = new DateTime(2025, 12, 8) },
            new() { Id = 6, Name = "Pallet Jack", Location = "Loading Dock", LastInspected = new DateTime(2026, 2, 22) },
            new() { Id = 7, Name = "Air Compressor", Location = "Utility Room", LastInspected = new DateTime(2026, 4, 5) },
        };
    }
}

@page "/inventory"
@rendermode InteractiveServer
@attribute [StreamRendering]
@using InventoryApp.Models
@using InventoryApp.Services
@inject EquipmentService EquipmentService
@inject PersistentComponentState PersistentState
@implements IDisposable

<PageTitle>Inventory</PageTitle>

<h1>Equipment Inventory</h1>

@if (_items is null)
{
    <p><em>Loading inventory...</em></p>
}
else
{
    <table class="table">
        <thead>
            <tr>
                <th>Id</th>
                <th>Name</th>
                <th>Location</th>
                <th>Last Inspected</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var item in _items)
            {
                <tr>
                    <td>@item.Id</td>
                    <td>@item.Name</td>
                    <td>@item.Location</td>
                    <td>@item.LastInspected.ToShortDateString()</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<EquipmentItem>? _items;
    private PersistingComponentStateSubscription _persistingSubscription;

    protected override async Task OnInitializedAsync()
    {
        _persistingSubscription = PersistentState.RegisterOnPersisting(PersistData);

        if (!PersistentState.TryTakeFromJson<List<EquipmentItem>>("inventory", out var restored))
        {
            // First render (prerender): fetch from service
            _items = await EquipmentService.GetEquipmentAsync();
        }
        else
        {
            // Interactive activation: use persisted data, no second fetch
            _items = restored;
        }
    }

    private Task PersistData()
    {
        PersistentState.PersistAsJson("inventory", _items);
        return Task.CompletedTask;
    }

    public void Dispose()
    {
        _persistingSubscription.Dispose();
    }
}

